fun solve(landStartTime: Array<Long>, landDuration: Array<Long>, waterStartTime: Array<Long>, waterDuration: Array<Long>): Long {
    val n = landStartTime.size
    val m = waterStartTime.size

    val landEndTimes = mutableListOf<LongArray>()
    val waterEndTimes = mutableListOf<LongArray>()

    // Calculate end times for land attractions (assuming they are chosen first)
    for (i in 0 until n) {
        val end = landStartTime[i] + landDuration[i]
        landEndTimes.add(LongArray(intArrayOf(end, i)))
    }

    // Calculate end times for water attractions (assuming they are chosen first)
    for (j in 0 until m) {
        val end = waterStartTime[j] + waterDuration[j]
        waterEndTimes.add(LongArray(intArrayOf(end, j)))
    }

